import sys
from collections import defaultdict, Counter

def load(path):
    table = defaultdict(dict)   # table[lemma][bundle] = form
    rows = []
    with open(path, encoding='utf-8') as f:
        for line in f:
            line = line.rstrip('\n').rstrip('\r')
            if not line.strip():
                continue
            lemma, form, feats = line.split('\t')
            bundle = tuple(feats.split(';'))
            table[lemma][bundle] = form
            rows.append((lemma, bundle, form))
    return table, rows

def lcp(a, b):
    n = 0
    while n < len(a) and n < len(b) and a[n] == b[n]:
        n += 1
    return n

def predict(table, L, B, exclude=None):
    """Predict form for lemma L, bundle B, using analogy over other lemmas.
    exclude: a (lemma,bundle) cell to pretend is absent (for LOO)."""
    def get(lem, bun):
        if (lem, bun) == exclude:
            return None
        return table[lem].get(bun)

    Lcells = {P: get(L, P) for P in table[L] if get(L, P) is not None and P != B}
    votes = Counter()
    for D in table:
        if D == L:
            continue
        DB = get(D, B)
        if DB is None:
            continue
        for P, LP in Lcells.items():
            DP = get(D, P)
            if DP is None:
                continue
            # transformation D: P -> B  (prefix preserved)
            p = lcp(DP, DB)
            donor_suf_P = DP[p:]
            donor_suf_B = DB[p:]
            if LP.endswith(donor_suf_P):
                stem = LP[:len(LP) - len(donor_suf_P)]
                pred = stem + donor_suf_B
                # weight: similarity of D and L over shared cells
                votes[pred] += 1
    if not votes:
        return None
    return votes.most_common(1)[0][0]

if __name__ == '__main__':
    table, rows = load('/workspace/data/izh.trn')
    correct = 0
    total = 0
    wrong = []
    for (L, B, gold) in rows:
        pred = predict(table, L, B, exclude=(L, B))
        total += 1
        if pred == gold:
            correct += 1
        else:
            wrong.append((L, ';'.join(B), gold, pred))
    print(f"LOO accuracy: {correct}/{total} = {correct/total:.4f}")
    print("--- sample wrong ---")
    for w in wrong[:40]:
        print(w)

