import sys
from collections import defaultdict, Counter

def load(path):
    table = defaultdict(dict)
    rows = []
    with open(path, encoding='utf-8') as f:
        for line in f:
            line = line.rstrip('\n').rstrip('\r')
            if not line.strip():
                continue
            lemma, form, feats = line.split('\t')
            fl = feats.split(';')
            bundle = tuple(fl[1:])
            table[lemma][bundle] = form
            rows.append((lemma, bundle, form, feats))
    return table, rows

def lcp(a, b):
    n = 0
    while n < len(a) and n < len(b) and a[n] == b[n]:
        n += 1
    return n

def apply_pair(table, P, B, Lform, skip_lemma):
    """Using all lemmas (except skip_lemma) having both P and B, learn suffix
    rules P->B and apply to Lform. Return Counter of candidate outputs (voted)."""
    out = Counter()
    for D in table:
        if D == skip_lemma:
            continue
        DP = table[D].get(P); DB = table[D].get(B)
        if DP is None or DB is None:
            continue
        p = lcp(DP, DB)
        src, dst = DP[p:], DB[p:]
        if Lform.endswith(src):
            cand = Lform[:len(Lform) - len(src)] + dst
            out[cand] += len(src) + 1     # longer matched suffix = more specific
    return out

def build_reliability(table):
    """rel[(P,B)] = accuracy of predicting B from P across lemmas (LOO)."""
    cells = set()
    for L in table:
        cells |= set(table[L].keys())
    rel = {}
    for P in cells:
        for B in cells:
            if P == B:
                continue
            corr = tot = 0
            for L in table:
                if P in table[L] and B in table[L]:
                    votes = apply_pair(table, P, B, table[L][P], skip_lemma=L)
                    if votes:
                        pred = votes.most_common(1)[0][0]
                        tot += 1
                        if pred == table[L][B]:
                            corr += 1
            if tot >= 3:
                rel[(P, B)] = corr / tot
    return rel

def predict(table, rel, L, B, exclude=None):
    votes = Counter()
    for P in table[L]:
        if P == B:
            continue
        if (L, P) == exclude:
            continue
        r = rel.get((P, B))
        if r is None or r <= 0:
            continue
        cand = apply_pair(table, P, B, table[L][P], skip_lemma=L)
        if cand:
            pred = cand.most_common(1)[0][0]
            votes[pred] += r * r
    if not votes:
        return None
    return votes.most_common(1)[0][0]

if __name__ == '__main__':
    table, rows = load('/workspace/data/izh.trn')
    rel = build_reliability(table)
    correct = tot = 0
    wrong = []
    for (L, B, gold, feats) in rows:
        pred = predict(table, rel, L, B, exclude=(L, B))
        tot += 1
        if pred == gold:
            correct += 1
        else:
            wrong.append((L, feats, gold, pred))
    print(f"LOO accuracy: {correct}/{tot} = {correct/tot:.4f}")
    for w in wrong[:40]:
        print(w)

